using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Abbreviation = "CS" },
        new() { Id = 2, Name = "Mathematics", Abbreviation = "MATH" },
        new() { Id = 3, Name = "Physics", Abbreviation = "PHYS" },
        new() { Id = 4, Name = "English", Abbreviation = "ENG" },
        new() { Id = 5, Name = "History", Abbreviation = "HIST" },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, functions, and object-oriented basics.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a PhD from MIT and has published extensively on programming pedagogy.", DepartmentId = 1, IsFeatured = true },
        new() { Id = 2, Code = "CS 201", Title = "Data Structures and Algorithms", Description = "Study fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques (sorting, searching, dynamic programming).", Credits = 4, Schedule = "Tue/Thu 10:00–11:15 AM", InstructorName = "Dr. James Rodriguez", InstructorBio = "Dr. Rodriguez specializes in algorithm optimization and competitive programming. He previously worked at Google Research.", DepartmentId = 1, IsFeatured = true },
        new() { Id = 3, Code = "CS 310", Title = "Database Systems", Description = "Covers relational database design, SQL, normalization, transaction processing, and an introduction to NoSQL databases.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a PhD from MIT and has published extensively on programming pedagogy.", DepartmentId = 1, IsFeatured = false },
        new() { Id = 4, Code = "MATH 151", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Prof. Michael Torres", InstructorBio = "Prof. Torres is an award-winning educator with a focus on making calculus accessible. He has authored two popular textbooks.", DepartmentId = 2, IsFeatured = true },
        new() { Id = 5, Code = "MATH 250", Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications to data science and computer graphics.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Emily Park", InstructorBio = "Dr. Park researches applications of linear algebra in machine learning. She joined the faculty from a data science role at a Fortune 500 company.", DepartmentId = 2, IsFeatured = false },
        new() { Id = 6, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments.", Credits = 4, Schedule = "Tue/Thu 8:30–9:45 AM + Fri Lab 2:00–4:50 PM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is a former NASA researcher specializing in applied mechanics. He brings real-world physics applications to the classroom.", DepartmentId = 3, IsFeatured = false },
        new() { Id = 7, Code = "PHYS 220", Title = "Electromagnetism", Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves. Prerequisite: PHYS 101.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Lisa Wang", InstructorBio = "Dr. Wang's research focuses on quantum electrodynamics. She received the university's Distinguished Teaching Award in 2024.", DepartmentId = 3, IsFeatured = true },
        new() { Id = 8, Code = "ENG 110", Title = "Academic Writing", Description = "Develop skills in argumentation, research writing, and critical analysis. Emphasis on clear, persuasive prose.", Credits = 3, Schedule = "Mon/Wed 9:00–10:15 AM", InstructorName = "Prof. David Okafor", InstructorBio = "Prof. Okafor is a published novelist and essayist who has taught writing at the university level for over 20 years.", DepartmentId = 4, IsFeatured = false },
        new() { Id = 9, Code = "ENG 250", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present day, with attention to cultural and historical contexts.", Credits = 3, Schedule = "Tue/Thu 3:00–4:15 PM", InstructorName = "Dr. Amanda Fisher", InstructorBio = "Dr. Fisher specializes in 20th-century American fiction and has published in leading literary journals.", DepartmentId = 4, IsFeatured = false },
        new() { Id = 10, Code = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, events, and cultural developments from prehistory through the late medieval period.", Credits = 3, Schedule = "Tue/Thu 11:30 AM–12:45 PM", InstructorName = "Dr. Marcus Johnson", InstructorBio = "Dr. Johnson is an expert in ancient Mediterranean civilizations with extensive archaeological fieldwork experience.", DepartmentId = 5, IsFeatured = false },
    ];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();
}

